-- Run this once to populate your database
-- Only stores what restcountries.com can't give you: your custom descriptions
-- Everything else (name, capital, population, flag, region) is fetched live from the free API

CREATE TABLE IF NOT EXISTS countries (
    iso2 TEXT PRIMARY KEY,
    description TEXT NOT NULL
);

INSERT OR IGNORE INTO countries (iso2, description) VALUES

-- AFRICA
('DZ', 'One of Africa''s largest nations, Algeria was home to ancient Berber civilisations before Phoenician traders established coastal settlements. Rome later ruled much of the north, followed by Arab conquests in the 7th century that introduced Islam. Ottoman rule began in the 16th century and lasted until France invaded in 1830. A brutal independence war from 1954–1962 ended French colonial rule, and Algeria emerged as a socialist republic rich in oil and natural gas.'),
('AO', 'Angola''s history stretches back to the powerful Kingdom of Kongo, which dominated central-western Africa from the 14th century. Portuguese explorers arrived in the 1480s and Angola became a major source of enslaved people shipped to Brazil. After centuries of colonial rule, a long independence war ended in 1975, followed immediately by a devastating civil war that lasted until 2002. Today Angola is one of sub-Saharan Africa''s largest oil producers.'),
('BJ', 'Benin was once the seat of the Dahomey Kingdom, famed for its all-female warrior corps, the Agojie. The kingdom became a major player in the Atlantic slave trade before French colonisation in the late 19th century. Independent since 1960, Benin later became a pioneer of democratic transition in Africa in 1990. The country is considered the birthplace of Vodun (Voodoo), a spiritual tradition that spread to the Americas through the diaspora.'),
('BW', 'The Tswana people have inhabited the Kalahari region for centuries, establishing chieftaincies that resisted Zulu raids and Boer encroachment. Botswana became a British protectorate in 1885 and gained independence peacefully in 1966. The discovery of diamonds shortly after independence transformed the country into one of Africa''s fastest-growing economies. Botswana is widely cited as a model of good governance and conservation, protecting vast wildlife reserves including the Okavango Delta.'),
('BF', 'Burkina Faso, meaning "Land of Upright People," was home to the Mossi Kingdoms from the 11th century — powerful states that resisted Mali and Songhai expansion. French colonisers arrived in the 1890s and called the territory Upper Volta. After independence in 1960, the country endured multiple coups. Revolutionary leader Thomas Sankara ruled from 1983–1987, renaming the country and enacting radical social reforms before his assassination.'),
('BI', 'The Kingdom of Burundi dates to the 17th century, ruled by the Ganwa aristocracy under a mwami (king). German then Belgian colonial rule reinforced ethnic divisions between Hutu and Tutsi, sowing seeds of later conflict. Independent since 1962, Burundi suffered cycles of ethnic violence and civil war. It remains one of the world''s poorest and most densely populated countries, though peace has largely held since a 2005 power-sharing agreement.'),
('CV', 'An uninhabited archipelago when Portuguese navigators arrived in 1456, Cape Verde became a key hub in the Atlantic slave trade and later a refuelling stop for transatlantic voyages. A distinctive Creole culture blending African and European influences emerged over centuries. The islands gained independence in 1975 and have since built a stable democracy. Despite scarce natural resources, Cape Verde has achieved relatively high human development through tourism, remittances, and services.'),
('CM', 'Cameroon''s diverse landscape — from rainforest to savanna — mirrors its extraordinary cultural mosaic of over 280 ethnic groups. Portuguese sailors reached its coast in 1472. After German colonial rule, Britain and France divided the territory following WWI. The French section became independent in 1960 and merged with part of British Cameroon in 1961. Often called "Africa in miniature," Cameroon remains a stable but authoritarian state sitting atop significant oil reserves.'),
('CF', 'The landlocked Central African Republic sits at the heart of the continent with a history shaped by slave raids, French colonisation, and postcolonial instability. Independence came in 1960, but the country has experienced repeated coups, most infamously under self-proclaimed Emperor Jean-Bédel Bokassa in the 1970s. Rich in diamonds, gold, and uranium yet ranking among the world''s least developed nations, the CAR has suffered ongoing conflict between rebel factions since 2012.'),
('TD', 'Chad''s Lake Chad basin was one of Africa''s great crossroads, home to the ancient Kanem-Bornu empire that thrived for nearly a thousand years. French forces conquered the region by 1900. Since independence in 1960, Chad has endured continuous power struggles and conflict with Libya over the Aouzou Strip. Despite vast oil reserves discovered in the 1990s, Chad remains among the world''s most impoverished nations and faces ongoing insurgencies in its Sahel region.'),
('KM', 'The Comoros archipelago in the Indian Ocean was settled by Bantu-speaking peoples, Arab traders, and Shirazi Persians, creating a deeply Islamic Swahili culture. France colonised the islands in the 19th century and Comoros declared independence unilaterally in 1975. The country subsequently experienced more than 20 coups or coup attempts — earning a reputation as the world''s most coup-prone nation. Ylang-ylang and cloves remain major exports.'),
('CD', 'Home to the ancient Kingdom of Kongo, the territory now known as the Democratic Republic of Congo was claimed by Belgian King Leopold II as his personal property in 1885. His brutal rubber extraction regime killed millions. After Belgian colonial rule and independence in 1960, the country was plunged into crisis. Mobutu Sese Seko ruled for 32 years before being ousted in 1997. The country holds extraordinary mineral wealth — including cobalt critical for electric batteries — yet remains wracked by conflict in its eastern regions.'),
('CG', 'The Republic of Congo, sometimes called Congo-Brazzaville, was part of the French Congo colonial federation. Ancient Bantu kingdoms including the Loango once flourished here. After independence in 1960, the country swung between Marxist ideology and multiparty democracy, with oil revenues fuelling both development and corruption. The Congo River basin it shares contains the world''s second-largest tropical rainforest.'),
('CI', 'Long a patchwork of small kingdoms and chieftaincies, Côte d''Ivoire came under French influence in the 19th century. After independence in 1960, founding president Félix Houphouët-Boigny steered the "Ivorian Miracle" — decades of coffee and cocoa-driven growth. His death in 1993 sparked political instability and a civil war from 2002–2011. Today the country is the world''s largest cocoa producer and one of West Africa''s most dynamic economies.'),
('DJ', 'Situated at the mouth of the Red Sea, Djibouti has been a strategic trading crossroads for millennia. The Afar and Somali peoples have inhabited the region for centuries. France established a coaling station here in 1862 and ruled until independence in 1977. Djibouti''s economy revolves around its port, which handles the majority of landlocked Ethiopia''s trade. Its strategic location has made it host to multiple foreign military bases including American, French, and Chinese facilities.'),
('EG', 'Egypt is one of the cradles of human civilisation, with a continuous recorded history stretching back 5,000 years. The pharaonic era produced pyramids, hieroglyphics, and a rich religious tradition. Egypt was subsequently ruled by Persians, Greeks, Romans, Arab caliphates, the Ottomans, and briefly the French before becoming a British protectorate. Independence came in 1922. The 1952 revolution brought Gamal Abdel Nasser to power, nationalising the Suez Canal and transforming Arab politics.'),
('GQ', 'The only Spanish-speaking country in sub-Saharan Africa, Equatorial Guinea was carved from territories the Portuguese ceded to Spain in 1778. After independence in 1968, Francisco Macías Nguema ruled by terror until being overthrown by his nephew Teodoro Obiang in 1979. The discovery of offshore oil in the 1990s made Equatorial Guinea one of Africa''s wealthiest nations per capita, though most citizens remain poor.'),
('ER', 'Eritrea''s Red Sea coast was part of ancient Aksum and later controlled by Ottomans and Egyptians before Italy colonised it in 1889. After WWII, the UN federated Eritrea with Ethiopia, which then annexed it in 1962, triggering a 30-year independence war. Eritrea finally won independence in 1993, but a devastating border war with Ethiopia from 1998–2000 left lasting scars. Under President Isaias Afwerki, Eritrea operates one of Africa''s most closed, heavily militarised states.'),
('SZ', 'One of Africa''s last absolute monarchies, Eswatini (formerly Swaziland) has been ruled by the Swazi royal family for centuries. The kingdom survived Zulu pressure and British colonisation, becoming a protectorate in 1903 and gaining independence in 1968. King Mswati III renamed the country Eswatini in 2018. The country is heavily dependent on South Africa economically and faces a severe HIV/AIDS epidemic.'),
('ET', 'Ethiopia is one of the oldest nations in the world, with a history rooted in the ancient Aksumite Empire, one of antiquity''s great trading powers. Christianity arrived in the 4th century and Ethiopia has been predominantly Christian ever since. Crucially, Ethiopia was never colonised — defeating Italy at the Battle of Adwa in 1896. Emperor Haile Selassie modernised the country until being ousted in 1974 by a Marxist junta. After decades of famine and civil war, Ethiopia today is Africa''s second most populous nation.'),
('GA', 'French explorers reached Gabon''s coast in the 1470s and it became a French colony in the 19th century. The country has been dominated since independence in 1960 by the Bongo family — Omar Bongo ruled for 42 years until his death in 2009, succeeded by his son Ali. Gabon''s oil wealth has delivered a relatively high standard of living compared to regional neighbours. Over 85% of the country is covered by rainforest, making it one of Africa''s most carbon-rich nations.'),
('GM', 'The Gambia, Africa''s smallest mainland nation, is a narrow sliver of land surrounding the Gambia River. It was a major transshipment point in the Atlantic slave trade. The British established control in the 19th century, and independence came in 1965. Dictator Yahya Jammeh ruled from 1994 to 2017, when he was ousted by a democratic election — a rare peaceful transition in the region. The Gambia remains one of the world''s poorest countries.'),
('GH', 'Ghana''s name honours the medieval Empire of Ghana, and its territory was once part of the Ashanti Kingdom — renowned for goldsmithing and military prowess. Europeans called it the Gold Coast, establishing trading forts from the 15th century. In 1957, Ghana became the first sub-Saharan African country to gain independence, under visionary leader Kwame Nkrumah. Today Ghana is one of West Africa''s most stable democracies and a major cocoa and gold exporter.'),
('GN', 'Home to ancient Mali and Songhai empire territories, Guinea''s coast attracted Portuguese traders from the 15th century. Guinea was the only French colony to vote "No" to de Gaulle''s proposed community in 1958, gaining immediate independence but facing French economic retaliation. The country sits atop the world''s largest bauxite reserves yet remains deeply poor. Military coups in 2008 and 2021 interrupted democratic progress.'),
('GW', 'A former Portuguese colony, Guinea-Bissau was a hub for the Atlantic slave trade. Amílcar Cabral led a revolutionary independence movement, assassinated in 1973 just before independence was formally recognised in 1974. The country has suffered extraordinary political instability — more than nine coups or coup attempts since independence. Despite its small size, Guinea-Bissau is one of the world''s largest cashew nut exporters, though it also became a major drug trafficking hub in the 2000s.'),
('KE', 'Kenya''s Rift Valley is considered the cradle of humanity, where some of the oldest hominin fossils have been found. Bantu, Nilotic, and Cushitic peoples settled the region over millennia. Arab traders built Swahili city-states along the coast before the Portuguese and later the British arrived. Kenya became a prized settler colony; the Mau Mau uprising of the 1950s hastened independence in 1963. Today Kenya is East Africa''s largest economy and a regional hub for technology and finance.'),
('LS', 'Lesotho is a mountainous kingdom entirely surrounded by South Africa. King Moshoeshoe I united Sotho-speaking clans in the early 19th century to resist Zulu and Boer raids, seeking British protection in 1868. Independence came in 1966. The highland terrain meant Lesotho escaped the most intense land seizures of the apartheid era. Water exports to South Africa and textile manufacturing are key industries.'),
('LR', 'Liberia was founded in 1822 as a resettlement colony for freed American slaves, established by the American Colonization Society. It declared independence in 1847 — Africa''s first republic. Civil wars from 1989–2003, marked by extreme brutality under warlords including Charles Taylor, killed hundreds of thousands. Nobel Peace Prize laureate Ellen Johnson Sirleaf helped rebuild the nation, serving as president 2006–2018.'),
('LY', 'Libya''s Mediterranean coast hosted ancient Phoenician and Greek colonies before Rome absorbed it. The Ottomans ruled for four centuries before Italy colonised Libya in 1911. Independence came in 1951. Muammar Gaddafi seized power in 1969 and ruled for 42 years until the 2011 Arab Spring uprising and NATO intervention led to his death and the country''s descent into civil war.'),
('MG', 'Madagascar separated from mainland Africa 88 million years ago, evolving extraordinary endemic wildlife. The first human settlers arrived by sea from Borneo around 350–550 CE. The Merina Kingdom unified much of the island by the early 19th century. France colonised Madagascar in 1896. After independence in 1960, the country has struggled with chronic poverty and political instability. Over 90% of its wildlife exists nowhere else on Earth.'),
('MW', 'The Maravi Kingdom dominated the region from the 16th century. Scottish missionary David Livingstone explored the area in the 1850s, and the territory became a British protectorate in 1891 as Nyasaland. Independence came in 1964 under Hastings Banda, who ruled as dictator until multiparty elections in 1994. Malawi is one of the world''s least developed countries, landlocked and densely populated, yet renowned for its warm people and the spectacular freshwater Lake Malawi.'),
('ML', 'Mali was the heartland of three of West Africa''s greatest empires — Ghana, Mali, and Songhai — which controlled trans-Saharan gold and salt trade routes for over a thousand years. Timbuktu was a medieval centre of Islamic scholarship. French colonisation came in the late 19th century; independence followed in 1960. Military coups have repeatedly disrupted democratic governance, most recently in 2020 and 2021. Northern Mali has been destabilised by Tuareg rebellions and jihadist insurgencies since 2012.'),
('MR', 'Mauritania''s Saharan territory was home to ancient Berber and later Arab tribes who dominated trans-Saharan trade. The Almoravid dynasty, which spread Islam to West Africa and conquered Spain, originated here in the 11th century. France colonised the area in the early 20th century. Independent since 1960, Mauritania was the last country in the world to formally abolish slavery (1981) and only criminalised it in 2007. Vast iron ore deposits and fishing grounds are key economic resources.'),
('MU', 'Mauritius was uninhabited when Arab and Portuguese sailors discovered it. The Dutch introduced sugarcane and drove the dodo to extinction. France took control in 1715, then Britain in 1810. After emancipation, the British brought hundreds of thousands of indentured labourers from India, shaping a uniquely diverse society. Independence came in 1968; Mauritius has since become one of Africa''s most prosperous and democratic nations.'),
('MA', 'One of the ancient crossroads of civilisation, Morocco was home to Berber (Amazigh) peoples for millennia before Phoenician, Carthaginian, and Roman settlement. Arab conquest in the 7th century brought Islam. The Almoravid and Almohad dynasties built empires stretching into Spain. Morocco was never fully conquered by the Ottomans, maintaining its own sultanic dynasty. France and Spain divided the country into protectorates in 1912; independence followed in 1956. Morocco is Africa''s largest phosphate exporter.'),
('MZ', 'Mozambique''s Indian Ocean coastline attracted Arab and Swahili traders for centuries before Vasco da Gama arrived in 1498. Portugal ruled for nearly 500 years. A ten-year liberation war ended with independence in 1975, but a devastating civil war raged until 1992, killing around a million people. Mozambique has since rebuilt, though it remains one of the world''s poorest countries and faces renewed insurgency in its gas-rich north.'),
('NA', 'Namibia''s vast, arid landscapes were home to San hunter-gatherers, Nama, Damara, Herero, and Ovambo peoples. Germany colonised the territory in 1884 and committed one of history''s first genocides against the Herero and Nama (1904–1908). South Africa administered it until independence in 1990, implementing apartheid. Namibia is notable for strong conservation policies and is home to the Namib Desert — the world''s oldest desert — and iconic Sossusvlei dunes.'),
('NE', 'Landlocked at the edge of the Sahara, Niger''s territory was crossed by trans-Saharan trade routes for centuries and was home to the Songhai and Hausa kingdoms. French colonisation consolidated by 1900. Independent since 1960, Niger has experienced multiple coups and holds some of the world''s largest uranium deposits, yet remains the lowest ranked on the UN Human Development Index. A military coup in July 2023 ousted the elected government.'),
('NG', 'Nigeria is Africa''s most populous nation and largest economy. Its territory encompassed the ancient Nok culture, the Benin Kingdom, and the Sokoto Caliphate. British colonisation amalgamated diverse ethnic groups into a single state in 1914. Independence came in 1960, followed by a brutal civil war (the Biafran War, 1967–1970) and decades of military rule. Nigeria is the world''s sixth-largest oil producer and home to Nollywood — the world''s second-largest film industry.'),
('RW', 'Rwanda was a centralised kingdom under the Mwami for centuries before German and then Belgian colonial rule. Belgians institutionalised ethnic distinctions between Hutu and Tutsi, fuelling the 1994 genocide in which around 800,000 Tutsi and moderate Hutu were killed in 100 days. From this catastrophe, Rwanda has undertaken a remarkable reconstruction — achieving rapid economic growth, gender equality in parliament, and environmental leadership.'),
('ST', 'These volcanic islands in the Gulf of Guinea were uninhabited when Portuguese sailors discovered them around 1470. They became the first major sugar-producing colony in the world, worked by enslaved Africans. A distinctive Creole culture developed over centuries. Independence came in 1975. Despite small size and limited resources, São Tomé has maintained democratic governance.'),
('SN', 'Senegal''s history includes the medieval Jolof Empire and the great trading city of Saint-Louis, established by France in 1659 as its first sub-Saharan settlement. Senegal became a centrepiece of French West Africa. Independence came in 1960 under poet-president Léopold Sédar Senghor, who peacefully transferred power in 1980 — a rare African precedent. Senegal has never experienced a military coup and is one of West Africa''s most stable democracies.'),
('SL', 'Sierra Leone''s coastline was visited by Portuguese sailors who named it "Lion Mountains." Freetown was founded in 1792 as a home for freed slaves. Britain made it a crown colony in 1808. Independence came in 1961. A brutal civil war from 1991–2002, characterised by the RUF rebel movement''s amputations and child soldiers, devastated the country. Sierra Leone is a major diamond producer.'),
('SO', 'Somalia''s coastline was part of ancient trade networks with Egypt, Arabia, and India. Medieval Somali sultanates controlled the Indian Ocean horn. The 1991 collapse of the Siad Barre government plunged Somalia into civil war and statelessness that lasted decades, marked by famine, piracy, and the rise of Al-Shabaab militants. A federal government was re-established in 2012 and has been slowly consolidating control.'),
('ZA', 'South Africa''s San people are among humanity''s oldest continuous populations. Dutch settlers founded Cape Town in 1652. The discovery of diamonds (1867) and gold (1886) transformed the region and sparked the Anglo-Boer Wars. The Union of South Africa in 1910 entrenched white minority rule, culminating in the apartheid system (1948–1994). Nelson Mandela''s release and the transition to democracy in 1994 remains one of history''s most celebrated political transformations.'),
('SS', 'South Sudan became the world''s newest country in 2011 after a 2005 peace deal ended Africa''s longest civil war. The predominantly Christian and animist south had resisted Arab-Muslim rule from Khartoum for decades. Tragically, independence was followed by another civil war (2013–2018) between forces loyal to President Salva Kiir and former VP Riek Machar. South Sudan has significant oil reserves that remain its economic lifeline.'),
('SD', 'Sudan was home to ancient Nubia and the Kingdom of Kush, which rivalled and occasionally conquered pharaonic Egypt. Arab migrations brought Islam from the 7th century onward. Decades of civil war and the Darfur genocide from 2003 marked the Bashir era. The 2019 popular revolution ousted Omar al-Bashir after 30 years. A 2021 military coup derailed the democratic transition; civil war erupted in 2023, triggering one of the world''s worst humanitarian crises.'),
('TZ', 'Tanzania''s mainland (Tanganyika) and the Zanzibar archipelago united in 1964. Zanzibar was a great Swahili trading empire and the centre of the Arab slave trade in East Africa. Julius Nyerere led independence in 1961 and pursued "Ujamaa" (African socialism). Tanzania is home to Kilimanjaro — Africa''s highest peak — and the Serengeti''s legendary wildlife migrations.'),
('TG', 'The small coastal nation of Togo was a major slave-trading zone before becoming a German colony in 1884. After WWI it was split between Britain and France; the French portion became independent Togo in 1960. General Gnassingbé Eyadéma seized power in 1967 and ruled until his death in 2005, when his son Faure Gnassingbé controversially succeeded him. Togo is the world''s fourth-largest phosphate producer.'),
('TN', 'Tunisia was home to the great city of Carthage, which rivalled Rome for dominance of the Mediterranean before its destruction in 146 BCE. Independence came in 1956 under Habib Bourguiba, who modernised the country and expanded women''s rights. In 2011, Mohamed Bouazizi''s self-immolation sparked the Jasmine Revolution — the catalyst for the Arab Spring — making Tunisia the only country where it led to lasting democracy, though authoritarian backsliding resumed after 2021.'),
('UG', 'The Kingdom of Buganda was one of East Africa''s most sophisticated states when British colonial rule arrived in the 1890s. Uganda gained independence in 1962 under Milton Obote. Idi Amin''s brutal regime (1971–1979) killed hundreds of thousands and expelled Uganda''s Asian community. Yoweri Museveni came to power in 1986 and has ruled since. Uganda is famed for its mountain gorilla populations and the source of the Nile at Lake Victoria.'),
('ZM', 'Zambia''s territory was home to the ancient Bantu kingdoms of Lozi and Bemba. David Livingstone explored the Zambezi River in the 1850s, and British South Africa Company control followed. The territory was called Northern Rhodesia until independence in 1964. Zambia''s copper belt made it one of Africa''s wealthiest nations at independence, but falling copper prices and mismanagement caused economic decline. Zambia became the first sub-Saharan African country to default on its debt in the post-COVID era (2020).'),
('ZW', 'Zimbabwe takes its name from Great Zimbabwe, a massive stone city built between the 11th and 15th centuries by the Shona people. British colonist Cecil Rhodes''s company seized the land in the 1890s, creating Southern Rhodesia. A white minority government declared UDI in 1965; after a liberation war, independence came in 1980 under Robert Mugabe. His long rule ended with controversial land reforms, hyperinflation, and economic collapse before a 2017 military coup removed him.'),

-- ASIA
('AF', 'Situated at the crossroads of Central, South, and West Asia, Afghanistan has been a highway for conquering armies — Alexander the Great, Genghis Khan, Timur — and a graveyard for empires. The modern state took shape in 1747 under Ahmad Shah Durrani. A Soviet invasion in 1979 sparked a decade-long war; subsequent civil war brought the Taliban to power (1996–2001). After 20 years of US-led presence, the Taliban retook power in August 2021.'),
('AM', 'Armenia was the first nation to adopt Christianity as a state religion in 301 CE. The ancient Kingdom of Urartu preceded a series of Armenian kingdoms. The Armenian Genocide of 1915–1916, carried out by the Ottoman government, killed an estimated 1–1.5 million Armenians. Soviet rule lasted until independence in 1991. A war with Azerbaijan over Nagorno-Karabakh erupted multiple times; Azerbaijan''s 2023 offensive ended Armenian presence in the enclave.'),
('AZ', 'Azerbaijan straddles the Caucasus, where Zoroastrianism originated amid its natural gas fires — the "land of fire." Ruled by Persians, Arabs, Mongols, and Safavids before Russian annexation in the 19th century. Soviet Azerbaijan became independent in 1991. The country fought two wars with Armenia over Nagorno-Karabakh, gaining control of most disputed territories in 2020. Baku''s oil wealth has transformed it into a gleaming modern city.'),
('BH', 'This small archipelago in the Persian Gulf was the centre of the ancient Dilmun civilisation, a Bronze Age trading hub mentioned in Sumerian texts as paradise. Bahrain was one of the first Gulf states to discover oil (1932). Independence came in 1971. The Arab Spring of 2011 brought major protests by the Shia majority against the Sunni Al Khalifa rulers, suppressed with Saudi military assistance.'),
('BD', 'Bangladesh occupies the Bengal delta, one of the world''s most fertile and densely populated regions. Part of British India until 1947, it became East Pakistan — separated from West Pakistan by 1,600 km of Indian territory. Cultural and political tensions culminated in the 1971 Liberation War, in which Pakistani forces committed genocide before India''s intervention secured independence. Bangladesh has since made remarkable development gains in textiles, women''s education, and poverty reduction.'),
('BT', 'The Land of the Thunder Dragon has been a Buddhist kingdom for centuries, isolated by the Himalayas. Zhabdrung Ngawang Namgyal unified Bhutan in the 17th century. It avoided colonisation and only opened to foreign tourists in 1974, introduced television in 1999, and transitioned to constitutional monarchy in 2008. Famous for measuring progress by "Gross National Happiness" rather than GDP, Bhutan is a global model for sustainable development.'),
('BN', 'At its height in the 15th–16th centuries, the Sultanate of Brunei controlled much of Borneo and the Philippines. British protection began in 1888. Brunei chose not to join Malaysia at independence in 1984, becoming a wealthy oil-state sultanate. Sultan Hassanal Bolkiah has ruled since 1967. Brunei''s citizens enjoy free healthcare, education, and no income tax, funded by petroleum revenues.'),
('KH', 'Cambodia was the heartland of the Khmer Empire (802–1431 CE), which built Angkor Wat — the world''s largest religious monument. After Angkor''s fall, French colonisation came in 1863. The Khmer Rouge under Pol Pot (1975–1979) carried out one of history''s most devastating genocides, killing an estimated 1.5–2 million people — roughly a quarter of Cambodia''s population. UN-supervised elections in 1993 began a slow recovery.'),
('CN', 'China''s civilisation is among the world''s oldest, with continuous written records for over 3,000 years. Dynasties from the Shang to the Qing built the Great Wall and invented paper, printing, gunpowder, and the compass. The Qing Dynasty collapsed in 1912. After decades of civil war, the Communist Party under Mao Zedong founded the People''s Republic in 1949. Deng Xiaoping''s 1978 reforms launched China''s extraordinary economic rise, transforming it into the world''s second-largest economy.'),
('CY', 'Cyprus has been inhabited since 10,000 BCE and gave copper its name. Ancient Greeks, Persians, Romans, Byzantines, Crusaders, Venetians, and Ottomans all ruled the island. Britain took control in 1878 and Cyprus gained independence in 1960. Turkey invaded in 1974 following a Greek-backed coup, and the island has been divided ever since. The Greek Cypriot south is an EU member; the Turkish Republic of Northern Cyprus is recognised only by Turkey.'),
('GE', 'One of the world''s oldest wine cultures, Georgia has a history stretching back to the ancient kingdoms of Colchis and Iberia. It converted to Christianity in 327 CE. The medieval Georgian Kingdom reached its zenith under Queen Tamar (1184–1213). Mongols, Persians, and Ottomans all ravaged Georgia before it sought Russian protection in 1783. Soviet rule lasted until independence in 1991. Russia briefly invaded in 2008 in a war over South Ossetia.'),
('IN', 'India is one of the world''s oldest civilisations, home to the Indus Valley Civilisation (3300 BCE), the Vedic period, the Maurya and Gupta empires, and the Mughal Empire. Britain''s East India Company gradually took control in the 18th–19th centuries. Mahatma Gandhi''s non-violent independence movement led to independence in 1947 and a painful partition creating Pakistan. India is now the world''s largest democracy and most populous nation.'),
('ID', 'Indonesia is the world''s largest archipelago nation, comprising over 17,000 islands. The Hindu-Buddhist empires of Srivijaya and Majapahit dominated maritime Southeast Asia before Islamic sultanates spread from the 13th century. The Dutch East India Company arrived in 1602; Dutch colonial rule lasted until Japan''s WWII occupation. Sukarno declared independence in 1945. Suharto''s "New Order" (1966–1998) brought economic growth and brutal repression before democratic transition.'),
('IR', 'Iran (Persia) is one of the world''s oldest civilisations — home to the Achaemenid Empire, the ancient world''s largest. Cyrus the Great''s decree of religious tolerance is considered an early human rights document. Iran adopted Shia Islam under the Safavid dynasty (1501). The 1979 Islamic Revolution under Ayatollah Khomeini transformed Iran into a theocratic republic, reshaping Middle Eastern geopolitics ever since.'),
('IQ', 'Mesopotamia — the land between the Tigris and Euphrates — is the cradle of civilisation, where writing, the wheel, and the first cities were invented. Babylon, Assyria, and Akkad rose and fell here. Arab conquest in the 7th century established the Abbasid Caliphate, making Baghdad a world capital of learning. Ottoman rule lasted until WWI; Britain administered the modern state before independence in 1932. A US-led invasion in 2003 toppled Saddam Hussein, unleashing sectarian conflict.'),
('IL', 'The land of Israel is central to the Abrahamic faiths of Judaism, Christianity, and Islam. Ancient Hebrew kingdoms gave way to Persian, Greek, Roman, Byzantine, Arab, Crusader, and Ottoman rule. The Zionist movement of the late 19th century sought a Jewish homeland; Britain''s Balfour Declaration (1917) supported this. After the Holocaust, the UN proposed partition in 1947; Israel declared independence in 1948, triggering the first Arab-Israeli War — a conflict whose consequences continue to define the Middle East.'),
('JP', 'Japan''s history spans 30,000 years of human habitation. The imperial institution dates to legendary 660 BCE. Buddhism arrived from Korea in 552 CE alongside Chinese cultural influence. Japan''s feudal era produced the samurai code and Zen aesthetics. The Meiji Restoration (1868) rapidly modernised Japan along Western lines. Japan''s postwar "economic miracle" made it the world''s second-largest economy by 1968; it remains a global powerhouse of technology and culture.'),
('JO', 'Jordan''s territory hosted ancient civilisations including the Nabataeans, whose rose-red city of Petra is among the world''s most spectacular archaeological sites. The region passed through Persian, Greek, Roman, Byzantine, and Arab hands before Ottoman control for four centuries. Britain carved the Emirate of Transjordan in 1921; independence came in 1946. King Hussein navigated the Cold War and multiple Arab-Israeli conflicts with remarkable diplomatic skill. Jordan remains an island of relative stability in a turbulent region.'),
('KZ', 'The vast steppes of Kazakhstan were the original homeland of nomadic horseback culture and the birthplace of the domesticated horse around 3500 BCE. The Silk Road passed through its oases. Russian conquest came in the 18th–19th centuries. Soviet Kazakhstan suffered enormously during collectivisation — the 1930s famine killed over a million people. Kazakhstan gained independence in 1991; Nursultan Nazarbayev ruled until 2019, transforming Astana into a gleaming new capital.'),
('KW', 'Kuwait was settled by Arab tribes in the early 18th century and became a British protectorate in 1899. Oil was discovered in 1938, transforming the small fishing port into an immensely wealthy state. Independence came in 1961. Iraq''s invasion and annexation of Kuwait in 1990 led to the Gulf War (1991), in which a US-led coalition expelled Iraqi forces. Kuwait''s parliament is one of the most active in the Gulf.'),
('KG', 'The Kyrgyz people have a rich nomadic heritage celebrated in the epic poem Manas — the world''s longest epic at over 500,000 lines. The territory was dominated by various Turkic and Mongol empires before Russian conquest in the 1860s. Independence came in 1991. Kyrgyzstan has experienced two popular uprisings (2005 and 2010) that overthrew presidents, earning a reputation as Central Asia''s most politically open, if unstable, country.'),
('LA', 'The Lao kingdom of Lan Xang ("Million Elephants") was founded in 1353. A brutal CIA secret war during the Vietnam War era made Laos the most heavily bombed country per capita in history. The Communist Pathet Lao took power in 1975 and has ruled since. Laos is opening its economy through hydropower exports and tourism while remaining one of Southeast Asia''s least developed nations.'),
('LB', 'Lebanon''s Phoenician coast was home to the world''s greatest ancient seafarers and traders, who spread the alphabet across the Mediterranean. Independence came in 1943. Sectarian tensions exploded in a 15-year civil war (1975–1990). Reconstruction made Beirut the "Paris of the Middle East," before the 2019 economic collapse — one of the worst in modern history — and the catastrophic Beirut port explosion of 2020.'),
('MY', 'Malaysia''s Malay Peninsula was home to the great Sultanate of Malacca (1400–1511), the hub of Southeast Asian spice trade, before Portuguese, Dutch, and British colonisation. Independence came in 1957. Under Mahathir Mohamad''s long rule (1981–2003), Malaysia transformed into an industrial economy. The Petronas Twin Towers were briefly the world''s tallest buildings. Malaysia remains a major Muslim-majority democracy and manufacturing hub.'),
('MV', 'The Maldives archipelago of 1,200 coral islands has been settled for at least 3,500 years. The islands converted to Islam in 1153. Independence came in 1965. The Maldives faces an existential threat from rising seas — most of the islands sit just 1–2 metres above sea level, making it climate change''s most vulnerable nation.'),
('MN', 'In 1206, Genghis Khan united warring Mongol tribes and forged the largest contiguous empire in history, stretching from Korea to Hungary. The empire''s Pax Mongolica connected East and West, facilitating trade and the spread of the Black Death. Outer Mongolia came under Chinese Qing control and then became a Soviet satellite state in 1924. Independence came in 1990 with a peaceful democratic revolution. Mongolia remains one of the world''s most sparsely populated countries.'),
('MM', 'Burma''s history is one of great kingdoms — the Pagan Empire, Toungoo, and Konbaung dynasties — before British annexation. Independence came in 1948. General Ne Win''s 1962 coup began decades of military rule and isolation. A partial democratic opening from 2011 brought Aung San Suu Kyi''s party to power in 2015. A military coup in February 2021 sparked mass protests and civil war, plunging the country into its worst crisis since independence.'),
('NP', 'Nepal is the birthplace of Siddhartha Gautama (the Buddha) and home to eight of the world''s ten highest mountains, including Everest. The Kathmandu Valley was seat of the Licchavi and Malla kingdoms before Prithvi Narayan Shah unified Nepal in 1768. Unlike most of South Asia, Nepal was never colonised. A decade-long Maoist insurgency (1996–2006) ended with peace talks; Nepal became a republic in 2008, ending 240 years of monarchy.'),
('KP', 'Korea was a unified peninsula with a rich 5,000-year history before Japan annexed it in 1910. Liberated at WWII''s end, Korea was divided at the 38th parallel. The Korean War (1950–1953) ended in armistice, not peace. North Korea under the Kim dynasty — Kim Il-sung, Kim Jong-il, and Kim Jong-un — has been one of history''s most isolated and totalitarian states. Its nuclear weapons programme has made it a defining challenge in global nonproliferation.'),
('OM', 'Oman''s coastline made it a seafaring power for millennia — Omani sailors navigated to India, East Africa, and China long before European exploration. The Ibadhi form of Islam, distinct from both Sunni and Shia, became Oman''s faith in the 8th century. The Al Said dynasty has ruled since 1744. Sultan Qaboos''s 50-year reign (1970–2020) modernised Oman dramatically. It practices a distinctively independent, balanced foreign policy.'),
('PK', 'The Indus Valley Civilisation, one of the world''s oldest, flourished in what is now Pakistan around 2500 BCE. The region saw Alexander the Great, the Maurya Empire, Arab Muslim conquest, Delhi Sultanate, Mughal Empire, and finally British rule. Partition from India in 1947 created Pakistan as the world''s first explicitly Islamic state. Since then, Pakistan has experienced four military coups, wars with India, and nuclear tests in 1998.'),
('PS', 'Palestine — the ancient land between the Jordan River and the Mediterranean — has been inhabited for hundreds of thousands of years. It was the heartland of ancient Canaanite and Israelite civilisations, and a crossroads for every empire from Egypt to Rome. The 1947 UN partition plan and the 1948 war created the refugee crisis. The Oslo Accords (1993) created limited Palestinian self-governance, but a final peace settlement remains elusive amid ongoing conflict.'),
('PH', 'The Philippines'' 7,641 islands were home to sophisticated trading kingdoms before Ferdinand Magellan arrived in 1521 and was killed by Chief Lapu-Lapu. Spain colonised the archipelago for 333 years, introducing Christianity. The US took control after the Spanish-American War (1898). Independence came in 1946. Ferdinand Marcos''s dictatorship (1972–1986) ended in the "People Power Revolution." The Philippines is Asia''s largest Catholic nation.'),
('QA', 'Qatar''s arid peninsula was home to nomadic tribes and pearl fishermen for centuries. The Al Thani family has ruled since the mid-19th century. The discovery of the world''s largest natural gas field transformed Qatar from one of the Gulf''s poorest states to its wealthiest per capita. Qatar hosts Al Jazeera, major US military bases, and hosted the 2022 FIFA World Cup — the first in the Middle East.'),
('SA', 'The Arabian Peninsula is the birthplace of Islam, where the Prophet Muhammad received revelations in the 7th century CE in Mecca and Medina — the faith''s holiest cities. In 1744, Muhammad ibn Saud allied with religious reformer Muhammad ibn Abd al-Wahhab, founding the dynasty that would create modern Saudi Arabia in 1932. Oil was discovered in 1938. Crown Prince Mohammed bin Salman has driven dramatic social and economic reforms since 2017.'),
('SG', 'Founded as a British trading post by Stamford Raffles in 1819, Singapore''s strategic location at the tip of the Malay Peninsula made it the lynchpin of British power in Asia. Devastatingly captured by Japan in 1942. Singapore joined Malaysia in 1963 but was expelled in 1965 — an independence Lee Kuan Yew famously declared in tears. Lee''s government then engineered a remarkable transformation: from third-world to first-world in a single generation, becoming one of the world''s richest city-states.'),
('KR', 'Korea''s Three Kingdoms period, the Silla unification, and the Joseon Dynasty (1392–1897) created one of Asia''s most coherent cultural traditions. Japanese colonisation (1910–1945) left deep scars. Division at independence and the Korean War left South Korea devastated. The subsequent "Miracle on the Han River" — transforming from war-torn poverty to the world''s 10th-largest economy in two generations — is one of history''s most remarkable development stories. South Korea is now a global leader in technology, pop culture, and cinema.'),
('LK', 'Sri Lanka (Ceylon) has a recorded history of over 3,000 years. The Sinhalese arrived from North India around 500 BCE; Buddhism arrived in the 3rd century BCE and shaped the island''s identity. Portugal, the Netherlands, and Britain successively colonised the coast. Independence came in 1948. A civil war between the government and Tamil Tiger (LTTE) separatists raged from 1983–2009. Sri Lanka faced a severe economic crisis in 2022, becoming the first Asia-Pacific nation since 1978 to default on its debt.'),
('SY', 'Damascus is one of the world''s oldest continuously inhabited cities, dating to at least 8,000 BCE. Syria was the heartland of ancient civilisations conquered by Egyptians, Assyrians, Persians, Greeks, Romans, and Byzantines before Arab Muslim conquest in 636 CE. The Umayyad Caliphate made Damascus the Islamic world''s capital. Hafez al-Assad''s dynasty took power in 1971; the 2011 Arab Spring uprising against his son Bashar sparked a catastrophic civil war that killed half a million and displaced half the population.'),
('TW', 'Taiwan was inhabited by Austronesian peoples for thousands of years before the Dutch and Spanish established trading posts in the 17th century. Japan controlled Taiwan from 1895–1945. After WWII and the Communist victory in China''s civil war, the Nationalist government retreated to Taiwan in 1949, establishing the Republic of China. Taiwan has since become a vibrant democracy and the world''s leading producer of advanced semiconductors, at the centre of US-China strategic competition.'),
('TJ', 'The Persian-speaking Tajiks are among Central Asia''s oldest peoples, descendants of the Bactrian and Sogdian civilisations that flourished along the ancient Silk Road. The Samanid Empire (819–999 CE) was a golden age of Persian culture. Russian conquest came in the 1860s–1880s. Independence in 1991 was followed immediately by a brutal civil war (1992–1997) that killed 100,000. President Emomali Rahmon has ruled since 1992, consolidating authoritarian control.'),
('TH', 'Thailand (Siam) is remarkable for being the only Southeast Asian country never colonised by a European power. The Sukhothai Kingdom (13th–15th centuries) is considered the cradle of Thai civilisation. King Chulalongkorn (1868–1910) modernised Siam and balanced British and French pressure. Modern Thailand has experienced 19 coups since 1932 but has also built a major tourism and manufacturing economy.'),
('TL', 'The eastern half of the Timor island was a Portuguese colony for nearly 450 years. Indonesia invaded in 1975 and occupied it until 1999 — a brutal occupation that killed an estimated 100,000–180,000 people. A 1999 UN-supervised referendum voted for independence; Indonesian militias responded with widespread destruction before international peacekeepers arrived. Timor-Leste became the world''s newest country in 2002.'),
('TR', 'Anatolia has been inhabited for 10,000 years and was home to the Hittites, Lydians, and Greeks before Roman then Byzantine rule. Seljuk Turks arrived in the 11th century; the Ottoman Empire they founded lasted 600 years, at its peak controlling the Middle East, North Africa, and southeastern Europe. WWI defeat led Mustafa Kemal Atatürk to found the modern secular Turkish Republic in 1923. Turkey joined NATO in 1952 and straddles Europe and Asia geographically and culturally.'),
('TM', 'Turkmenistan''s ancient Merv was one of the Silk Road''s greatest cities — a metropolis of 200,000 people until Mongol forces destroyed it in 1221. Russian conquest came in the 1880s. Independence came in 1991 under Saparmurat Niyazov, who built a cult of personality so extreme he renamed months after himself. Despite vast natural gas reserves, Turkmenistan is deeply isolated and authoritarian.'),
('AE', 'The UAE''s seven emirates were known as the "Pirate Coast" to the British, who established a protectorate in the 19th century. Pearling was the economy''s backbone until oil was discovered in Abu Dhabi in 1958. The federation was formed in 1971. Abu Dhabi''s oil wealth and Dubai''s entrepreneurial vision have transformed a desert into a global hub for finance, tourism, and logistics. The UAE was among the first Arab states to normalise relations with Israel (2020).'),
('UZ', 'Uzbekistan''s ancient Silk Road cities — Samarkand, Bukhara, and Khiva — were among the medieval world''s most magnificent centres of science, art, and trade. Timur (Tamerlane) built his vast 14th-century empire from Samarkand. Soviet collectivisation devastated the Aral Sea through cotton irrigation. Independence came in 1991 under Islam Karimov, whose brutal repression continued until his death in 2016. His successor has pursued cautious reforms and economic opening.'),
('VN', 'Vietnam has a 4,000-year history, much of it defined by resistance to foreign domination. China ruled northern Vietnam for 1,000 years. France colonised Vietnam in the 19th century; Japan occupied it in WWII. Ho Chi Minh declared independence in 1945, sparking the First Indochina War and then the Vietnam War against the US (1955–1975). Reunification under Communist rule in 1976 was followed by Doi Moi economic reforms in 1986, transforming Vietnam into a dynamic manufacturing economy.'),
('YE', 'Yemen''s ancient kingdom of Sheba (Saba) was a great trading power, controlling the incense and spice routes that connected Arabia to the Mediterranean. The Ottoman and British empires divided Yemen. Unification in 1990 was fragile. Houthi rebels captured Sanaa in 2014 and a Saudi-led military intervention in 2015 created what the UN called the world''s worst humanitarian crisis.'),

-- EUROPE
('AL', 'Albania''s Illyrian ancestors were one of Europe''s ancient peoples. The Ottoman Empire ruled for five centuries (1468–1912), during which most Albanians converted to Islam. Communist leader Enver Hoxha created one of the world''s most isolated and repressive states (1944–1991), banning all religion and building 700,000 bunkers across the tiny country. The transition to democracy was turbulent. Albania is now an EU candidate country.'),
('AD', 'Nestled in the Pyrenees between France and Spain, Andorra is one of Europe''s oldest states, traditionally said to have been created by Charlemagne in 805 CE. Since 1278, it has been governed under a unique feudal co-principality arrangement — its two heads of state are the Bishop of Urgell and the French president. Despite its miniature size, Andorra is a popular ski destination and tax haven.'),
('AT', 'Austria was the core of the Habsburg Empire, one of Europe''s longest-lasting dynastic powers, which ruled from 1282 to 1918 and at its peak controlled a vast multi-ethnic realm across Central Europe. Vienna was for centuries a capital of European culture — home to Mozart, Beethoven, Freud, and Klimt. Austria was annexed by Nazi Germany in 1938. After WWII and Allied occupation, Austria became an independent neutral state in 1955.'),
('BY', 'Belarus — the "White Russia" — was part of the Grand Duchy of Lithuania and then the Polish-Lithuanian Commonwealth before Russian Imperial rule from 1795. The country suffered catastrophically in WWII, losing a quarter of its population. Soviet Belarus became independent in 1991. Alexander Lukashenko has ruled since 1994 — after the 2020 disputed election, mass protests were brutally suppressed. Belarus grew increasingly dependent on Russia and is often called "Europe''s last dictatorship."'),
('BE', 'Belgium was created as an independent state in 1830 after revolution against Dutch rule, becoming Europe''s most industrialised nation. King Leopold II''s personal rule of the Congo Free State (1885–1908) was one of history''s most brutal colonial regimes. Belgium''s linguistic divide between Dutch-speaking Flanders and French-speaking Wallonia is a defining political tension. As home to EU and NATO headquarters, Brussels is effectively the capital of Europe.'),
('BA', 'Bosnia''s medieval kingdom was conquered by the Ottoman Empire in 1463; Sarajevo became an important Ottoman city. Austro-Hungarian rule from 1878 sparked Serbian nationalism; the assassination of Archduke Franz Ferdinand in Sarajevo in 1914 triggered WWI. Bosnia declared independence in 1992, triggering the Bosnian War and the Srebrenica genocide — Europe''s worst since WWII. The Dayton Agreement (1995) ended the war but left a complex, dysfunctional political structure.'),
('BG', 'The First Bulgarian Empire (681–1018) was one of medieval Europe''s most powerful states, creating the Cyrillic alphabet that now serves 250 million people. Byzantium reconquered Bulgaria before the Second Empire rose (1185–1396). Ottoman rule lasted five centuries. Liberation in 1878 with Russian help led to a modern Bulgarian state. Bulgaria joined NATO (2004) and the EU (2007).'),
('HR', 'Croatia''s coast was colonised by ancient Greeks and then Romans — Diocletian, born in what is now Split, built his vast retirement palace there, which now forms the medieval city''s core. Croatia accepted Hungarian sovereignty in 1102, then became part of the Habsburg Empire. Croatia declared independence in 1991, triggering a brutal war that ended in 1995. Croatia joined the EU in 2013.'),
('CZ', 'Bohemia was a powerful medieval kingdom at the centre of European politics; Prague was briefly Europe''s most important city under Holy Roman Emperor Charles IV. The Defenestration of Prague in 1618 sparked the Thirty Years'' War. Czech lands were absorbed into the Habsburg Empire for three centuries. Czechoslovakia was created in 1918 and destroyed by Hitler in 1938–1939. Communist rule ended with the peaceful 1989 Velvet Revolution. Slovakia separated peacefully in 1993; the Czech Republic joined the EU and NATO.'),
('DK', 'Denmark''s Viking Age (793–1066 CE) saw Danes raid, trade, and settle from North America to Russia. The medieval Danish kingdom at times controlled England and much of Scandinavia. Denmark and Norway were united for centuries; the loss of Norway (1814) reduced Denmark to its modern size. Today Denmark is known for its social democracy, high quality of life, and progressive governance. Greenland remains an autonomous territory within the Danish realm.'),
('EE', 'Estonia was colonised by German crusaders in the 13th century and ruled by Danes, Germans, Swedes, and Russians over subsequent centuries. A distinct Estonian national identity crystallised in the 19th-century "national awakening." Estonia declared independence in 1918, suffered Soviet occupation in 1940, German invasion, and Soviet re-occupation before independence was restored in 1991. Estonia rapidly became a digital pioneer — one of the world''s most wired societies and the birthplace of Skype.'),
('FI', 'Finland was a Swedish province for 600 years before Russia took it in 1809, granting broad autonomy as a Grand Duchy. Finland declared independence in 1917 after Russia''s revolution. The 1939–1940 Winter War against the Soviet Union, fought with remarkable tenacity, secured Finland''s independence. Finland''s neutral "Finlandisation" during the Cold War gave way to EU membership in 1995 and, after Russia''s 2022 invasion of Ukraine, NATO membership in 2023.'),
('FR', 'France has been a central actor in Western civilisation since ancient Gaul was conquered by Julius Caesar. The 1789 Revolution''s ideals of liberty, equality, and fraternity transformed global politics. Napoleon''s conquests spread revolutionary principles across Europe while ending in defeat at Waterloo. France built the world''s second-largest colonial empire. Two World Wars devastated France; the postwar European project — beginning with France and Germany''s reconciliation — has been France''s greatest legacy.'),
('DE', 'German-speaking lands were fragmented into hundreds of principalities until Otto von Bismarck unified them in 1871 under the Prussian-led German Empire. The Nazi regime''s Holocaust murdered six million Jews and millions of others; WWII killed 70–85 million people globally. Germany was divided East and West until reunification in 1990. From this history, Germany rebuilt itself as a model of democratic accountability, becoming Europe''s largest economy and a pillar of the EU.'),
('GR', 'Greece is the birthplace of Western democracy, philosophy, theatre, and the Olympic Games. Ancient Athens''s intellectual culture — Socrates, Plato, Aristotle — formed the foundation of Western thought. Alexander the Great spread Greek culture from Egypt to India. After four centuries of Ottoman rule, Greece''s War of Independence (1821) captured European imagination. Greece joined the EU in 1981 but faced a devastating debt crisis from 2010 requiring multiple international bailouts.'),
('HU', 'The Magyars swept into the Carpathian Basin from the eastern steppes around 895 CE, founding a kingdom that became a major medieval European power. Hungary converted to Christianity under King Stephen I around 1000 CE. The Ottoman Empire occupied central Hungary for 150 years after Mohács (1526). The 1956 Hungarian Revolution against Soviet rule was crushed but inspired the world. Hungary joined the EU and NATO in 2004 but under Viktor Orbán has increasingly clashed with EU democratic norms.'),
('IS', 'Iceland was settled by Norse Vikings around 874 CE and established the world''s first parliament, the Althing, in 930 CE — making it one of the earliest democracies. Iceland came under Norwegian then Danish rule; full sovereignty came in 1944. Iceland sits on the Mid-Atlantic Ridge, with intense volcanic activity. Iceland suffered one of the worst per-capita bank collapses in 2008 but recovered strongly. It is also notable for near-complete gender equality.'),
('IE', 'Celtic Ireland had a distinctive early medieval culture — monks preserved classical learning through the "Dark Ages." Norman conquest from England in 1169 began 750 years of English rule. The Great Famine (1845–1852) killed a million and drove two million to emigrate, permanently reshaping Ireland''s demography. Independence (1922) partitioned the island; the Troubles in Northern Ireland lasted until the Good Friday Agreement (1998). Ireland''s "Celtic Tiger" economy boomed before crashing in 2008 and recovering strongly.'),
('IT', 'Italy is the heir of Rome — the city-state that grew into an empire controlling the entire Mediterranean world. Roman law, Latin language, and Christian religion shaped all of Western civilisation. After Rome''s fall, Italian city-states — Florence, Venice, Milan — produced the Renaissance, the greatest flourishing of art in human history. Unification (Risorgimento) came only in 1861. Fascism under Mussolini led Italy into WWII on the losing side. Italy became a founding member of the EU.'),
('XK', 'Kosovo is a deeply contested territory — Serbs regard the medieval Battle of Kosovo (1389) against the Ottomans as sacred to national identity, while ethnic Albanians comprise over 90% of today''s population. NATO bombing of Serbia in 1999 ended Serbian control and established UN administration. Kosovo declared independence in 2008, recognised by over 100 countries but not by Serbia, Russia, or China.'),
('LV', 'Latvia''s Baltic coastline was a trading corridor for amber and furs from antiquity. German crusaders (Teutonic Knights) conquered the Latvian and Livonian tribes in the 13th century, beginning 700 years of foreign rule — successively German, Polish, Swedish, and Russian. Latvia declared independence in 1918 but was occupied by the Soviet Union in 1940. Independence was restored in 1991; Latvia joined NATO and the EU in 2004.'),
('LI', 'This tiny Rhine Valley principality has been ruled by the Liechtenstein family since 1719. The smallest German-speaking country, Liechtenstein is a constitutional monarchy and one of the world''s wealthiest nations per capita, its economy built on financial services, precision manufacturing, and low taxes. Liechtenstein is one of only two doubly landlocked countries in the world.'),
('LT', 'The Grand Duchy of Lithuania was medieval Europe''s largest state, stretching from the Baltic to the Black Sea by the 15th century. Unified with Poland in the Polish-Lithuanian Commonwealth, it was one of Europe''s most tolerant states. Russian partition ended Lithuanian sovereignty in 1795. Lithuania''s 1990 declaration of independence was the first in the Soviet Union, leading a chain reaction. It joined NATO and the EU in 2004.'),
('LU', 'Luxembourg''s massive medieval fortress made it "the Gibraltar of the North" — a strategic prize fought over by Burgundians, Habsburgs, Spaniards, French, Austrians, and Prussians for centuries. Guaranteed independence and neutrality in 1867, Luxembourg became a founding member of NATO and the EU. Luxembourg has become one of Europe''s wealthiest nations, serving as a hub for EU institutions, banking, and steel production.'),
('MT', 'Malta''s strategic location in the centre of the Mediterranean made it one of history''s most fought-over islands. Ancient temples predate Stonehenge. Phoenicians, Greeks, Romans, Arabs, Normans, Knights of St John, French, and British all ruled. In WWII, Malta withstood extraordinary aerial bombardment and was awarded the George Cross collectively. Independent since 1964, Malta joined the EU in 2004.'),
('MD', 'Moldova''s territory was part of the medieval Principality of Moldavia. Ottoman, Russian, and Romanian rule followed. Forcibly incorporated into the Soviet Union in 1940, Moldova declared independence in 1991. The Russian-speaking eastern strip (Transnistria) immediately broke away — it remains a breakaway state with Russian troops present. Moldova is Europe''s poorest country. After Russia''s 2022 Ukraine invasion, Moldova accelerated EU membership talks.'),
('MC', 'Monaco is the world''s most densely populated sovereign state and second-smallest by area. The Grimaldi family has ruled since 1297, making it Europe''s oldest ruling dynasty. Known globally for its Grand Prix motor race, Monte Carlo casino, and extraordinary concentration of wealth. Despite having no income tax, Monaco uses the euro and has close ties with France.'),
('ME', 'Montenegro — "Black Mountain" — was a unique medieval principality that successfully resisted Ottoman conquest. The Petrović-Njegoš dynasty ruled for centuries. Montenegro joined Serbia in 1918 and later Yugoslavia; independence was restored by referendum in 2006, separating from Serbia. The country joined NATO in 2017. Montenegro''s dramatic Adriatic coastline and medieval towns have made it an increasingly popular European destination.'),
('NL', 'The Dutch Republic of the 17th century was the world''s leading economic and maritime power — the first modern capitalist state, home to the first stock exchange and global trading empire. The Dutch Golden Age produced Rembrandt, Vermeer, and Spinoza. The Netherlands was occupied by Germany in WWII. It is now a founding EU member, home to the International Court of Justice, and known for cycling, progressive social policies, and vast tulip fields.'),
('MK', 'Macedonia was the ancient kingdom of Philip II and Alexander the Great, who conquered an empire stretching from Greece to India in the 4th century BCE. Subsequent rule by Romans, Byzantines, Bulgarians, Serbs, and Ottomans followed. As part of Yugoslavia and then independent since 1991, the country resolved a name dispute with Greece in 2019, adopting the name "North Macedonia." It joined NATO in 2020 and is an EU candidate country.'),
('NO', 'Norway''s Vikings were among history''s most far-ranging explorers, reaching North America (Vinland) around 1000 CE. Norwegian kings united Scandinavia at times; after union with Denmark and Sweden, Norway gained independence in 1905. WWII German occupation and Norwegian resistance are defining national memories. The discovery of North Sea oil in 1969 transformed Norway into one of the world''s wealthiest nations. Norway''s sovereign wealth fund — the world''s largest — holds over $1.7 trillion in assets.'),
('PL', 'The Polish-Lithuanian Commonwealth was Europe''s largest state in the 16th–17th centuries. Three successive partitions by Russia, Prussia, and Austria erased Poland from the map for 123 years. Reborn in 1918, Poland was then devastated by WWII — losing six million citizens, including three million Polish Jews in the Holocaust. Solidarity movement-led peaceful transition in 1989 was the first free election in the Communist bloc. Poland joined NATO (1999) and the EU (2004).'),
('PT', 'Portugal was the pioneer of the Age of Exploration. From the early 15th century, Portuguese navigators — Bartholomeu Dias, Vasco da Gama — mapped Africa''s coast and reached India. Portugal built the first truly global empire. The Carnation Revolution of 1974 — a peaceful military coup — ended 48 years of dictatorship and led to decolonisation. Portugal joined the EU in 1986.'),
('RO', 'Romanian identity is rooted in the Dacian people conquered by Rome in 106 CE — Romanians speak a Latin language and consider themselves heirs of Roman colonists. Vlad the Impaler (inspiration for Dracula) defended Wallachia against the Turks. Unification in 1859 and independence in 1878 created modern Romania. Under Ceaușescu''s extreme communist dictatorship (1965–1989), Romania suffered extraordinary deprivation. The violent 1989 revolution ended his rule; Romania joined NATO (2004) and the EU (2007).'),
('RU', 'Russia''s roots lie in the Viking-founded Kievan Rus and the medieval principalities that survived Mongol conquest. Moscow emerged as the dominant state; Ivan the Terrible became the first tsar in 1547. Peter the Great and Catherine the Great Westernised and expanded the empire. Revolution in 1917 brought the Bolsheviks; the Soviet Union became a superpower that defeated Nazi Germany. The USSR dissolved in 1991; Russia''s 2022 invasion of Ukraine triggered the largest European war since WWII.'),
('SM', 'San Marino claims to be the world''s oldest republic, founded in 301 CE by Marinus, a Christian stonecutter fleeing Roman persecution. The tiny mountain republic on Mount Titano in central Italy has maintained its independence through papal and medieval politics, Napoleon''s campaigns, and Italian unification. San Marino holds the curious distinction of having more cars than people.'),
('RS', 'Medieval Serbia reached its zenith under Emperor Stefan Dušan in the 14th century, before the Ottoman victory at the Battle of Kosovo (1389) defined Serbian national consciousness for centuries. Serbia gained autonomy within the Ottoman Empire in the 19th century and full independence in 1878. Wars in the 1990s under Slobodan Milošević brought NATO bombing and international isolation. After his death in The Hague, Serbia began a slow democratic transition and EU candidacy process.'),
('SK', 'Inhabited by Great Moravia''s Slavic civilisation in the 9th century, Slovakia was absorbed into the Hungarian Kingdom for nearly a thousand years. Slovak national identity emerged through 19th-century cultural revival. The 1989 Velvet Revolution ended communism; the Velvet Divorce of 1993 peacefully separated Slovakia from the Czech Republic. Slovakia joined NATO and the EU in 2004 and adopted the euro in 2009.'),
('SI', 'The westernmost of the South Slavic lands, Slovenia was part of the Holy Roman Empire and then the Habsburg Austrian monarchy for centuries. Slovenes had the highest standard of living in Yugoslavia. Slovenia declared independence in 1991; a brief 10-day war with Yugoslav federal forces resulted in minimal casualties. Slovenia was the first former Yugoslav republic to join both NATO and the EU (2004).'),
('ES', 'Spain''s Iberian Peninsula was home to Celtiberians, Phoenicians, Greeks, and Romans before the Visigoth kingdom fell to Muslim Umayyad conquest in 711. The Reconquista — Christian kingdoms gradually retaking the peninsula — culminated in 1492, the same year Columbus reached America. Spain built history''s first global empire. The Spanish Civil War (1936–1939) and Franco''s dictatorship (1939–1975) gave way to a remarkable democratic transition. Spain joined the EU in 1986.'),
('SE', 'Sweden was a great power in the 17th century, controlling much of the Baltic and northern Germany. After defeat in the Great Northern War (1721), Sweden shrank and adopted a path of peaceful development. Sweden has maintained 200 years of peace — the longest of any nation. The welfare state built in the 20th century became a global model. Sweden joined the EU in 1995 and, after Russia''s 2022 Ukraine invasion, joined NATO in 2024.'),
('CH', 'Switzerland''s Old Confederation began in 1291 when three forest cantons swore mutual assistance. The Confederation defeated Burgundy''s Charles the Bold in the 1470s. Swiss mercenaries served European courts for centuries (the Swiss Guard still protects the Pope). Switzerland''s neutrality was formally established at the Congress of Vienna (1815). The International Red Cross was founded in Geneva in 1863. Switzerland is famous for direct democracy, banking, watchmaking, and extraordinary quality of life.'),
('UA', 'Ukraine is home to Kievan Rus — the 9th-century state from which Russia, Ukraine, and Belarus all claim descent. The 1932–1933 Holodomor, a Soviet-engineered famine, killed 3.5–7.5 million Ukrainians. Ukraine declared independence in 1991 when the USSR dissolved. The 2014 Euromaidan revolution ousted a Russia-aligned president; Russia annexed Crimea and backed separatists in the east. Russia''s full-scale invasion in February 2022 triggered Europe''s largest war since WWII.'),
('GB', 'Britain''s history spans Roman conquest, Anglo-Saxon kingdoms, Viking raids, and Norman conquest in 1066. The Magna Carta (1215) established early principles of rule of law. Britain built the largest empire in history, covering a quarter of the world''s land surface — spreading English language, law, and culture globally. The Industrial Revolution began in Britain. After WWII Britain''s empire dissolved; the Brexit referendum of 2016 led to departure from the EU, redefining Britain''s place in the world.'),
('VA', 'Vatican City is the world''s smallest internationally recognised sovereign state — a 44-hectare enclave in Rome and headquarters of the Roman Catholic Church. The papacy once controlled vast territories in central Italy (the Papal States) until Italian unification stripped them away in 1870. The Lateran Treaty of 1929 created the Vatican as a sovereign entity. St Peter''s Basilica and the Sistine Chapel, with Michelangelo''s ceiling, make it one of the world''s great artistic treasures.'),

-- NORTH AMERICA
('AG', 'These twin islands in the Caribbean were settled by the Arawak and Carib peoples before Columbus arrived in 1493, naming Antigua after a Seville church. Britain colonised the islands in 1632, developing sugar plantations worked by enslaved Africans. Horatio Nelson''s HMS Dockyard at English Harbour served as the Royal Navy''s Caribbean base. Independence came in 1981. Antigua and Barbuda has 365 beaches — one for every day of the year — and tourism dominates the economy.'),
('BS', 'The Bahamas'' coral islands were inhabited by the Lucayan people when Columbus made his first landfall in the Americas in 1492 on San Salvador. Spain depopulated the islands by enslaving the Lucayans; British colonists resettled them from 1648. Nassau became a pirate haven in the early 18th century — home to Blackbeard and the Republic of Pirates. Independence came in 1973. The Bahamas is now a major tourism destination and offshore financial centre.'),
('BB', 'Uninhabited when English settlers arrived in 1627, Barbados became one of the wealthiest sugar colonies in the world, sustained by the brutal enslavement of hundreds of thousands of Africans. The "Barbados slave code" of 1661 became a template for slavery laws across the Americas. Independence came in 1966. Barbados removed the British monarch as head of state in 2021, becoming a republic. It is the birthplace of Rihanna and holds a proud cricketing tradition.'),
('BZ', 'Belize was the heartland of the ancient Maya civilisation, which built magnificent cities in the jungle — Caracol, Xunantunich, Lamanai. British settlers exploiting logwood arrived in the 17th century. British Honduras gained independence in 1981 as Belize. Guatemala long claimed the entire territory; a recent ICJ ruling is resolving the dispute. Belize is home to the second-largest barrier reef in the world and extraordinary Mayan archaeological sites.'),
('CA', 'Canada''s First Nations and Inuit peoples have lived on the land for at least 15,000 years. Norse explorers briefly settled around 1000 CE. France and Britain competed for the continent; Britain won after the Seven Years'' War (1763). Canada gradually gained independence, becoming fully sovereign in 1982 with the patriation of its constitution. Canada fought in both World Wars. Canada built one of the world''s most successful multicultural societies, vast natural resources, and a social safety net.'),
('CR', 'Spain colonised Costa Rica in the 16th century; its distance from colonial centres left it with fewer plantations and a more egalitarian society. Independence from Spain came in 1821. Most remarkably, Costa Rica abolished its military in 1948 — the only country to have done so constitutionally — and redirected defence spending toward education and health. This decision laid the foundation for a stable democracy and pioneering ecotourism economy.'),
('CU', 'Cuba''s Taíno and Ciboney peoples were decimated after Columbus arrived in 1492. Spain made Havana the "Key to the New World" — a vital port for treasure fleets. The Spanish-American War (1898) transferred Cuba to US influence. Fidel Castro''s 1959 revolution established the Western Hemisphere''s only Communist state. The Cuban Missile Crisis of 1962 brought the world to the brink of nuclear war. Despite US embargo, Cuba has maintained high literacy and healthcare standards.'),
('DM', 'Called the "Nature Isle of the Caribbean," Dominica''s rugged volcanic terrain protected it from large-scale plantation agriculture and allowed it to retain the Caribbean''s largest remaining indigenous Kalinago (Carib) population. France and Britain fought over the island before British control from 1805. Independence came in 1978. Hurricane Maria devastated Dominica in 2017; it has since rebuilt with a focus on becoming the world''s first climate-resilient nation.'),
('DO', 'Santo Domingo is the oldest continuously inhabited European settlement in the Americas, founded in 1498. The island of Hispaniola was Columbus''s first base. France took the western third (Haiti) in the 17th century while Spain held the east. The Dominican Republic declared independence from Haiti in 1844. Today the Dominican Republic is the Caribbean''s largest economy and a major tourist destination.'),
('SV', 'El Salvador was home to the Pipil people and the Mayan Cuzcatlán before Spanish conquest. The smallest and most densely populated Central American nation, it was a coffee republic dominated by a landowning oligarchy. The brutal civil war (1979–1992) killed 75,000. Post-war El Salvador was plagued by gang violence until President Nayib Bukele''s sweeping crackdown from 2022 dramatically reduced homicide rates and won him overwhelming popular support.'),
('GD', 'The "Spice Isle" for its nutmeg, mace, and cinnamon production, Grenada was inhabited by the Carib people who resisted French colonisation fiercely. Britain took Grenada in 1762. Independence came in 1974. A Marxist coup in 1979 and a 1983 internal power struggle led to a US invasion — "Operation Urgent Fury" — restoring order. Grenada is now a peaceful tourism and spice-exporting economy.'),
('GT', 'Guatemala was the heartland of the classic Maya civilisation, which reached its zenith around 250–900 CE. Tikal''s pyramids rose above the jungle canopy, housing a city of 100,000. Spanish conquest was swift and brutal. Decades of US-backed military dictatorships and a 36-year civil war (1960–1996) killed 200,000, mostly Maya civilians. Guatemala remains deeply unequal with a predominantly indigenous population.'),
('HT', 'Haiti''s Saint-Domingue was France''s most profitable colony — produced by 500,000 enslaved Africans under horrific conditions. The Haitian Revolution (1791–1804) was the only successful slave revolution in history and the first Black republic in the world. France forced Haiti to pay 150 million francs in reparations — a debt that strangled development for 122 years. A 2010 earthquake killed 200,000. Chronic political instability and gang control of Port-au-Prince have created a humanitarian catastrophe.'),
('HN', 'Honduras was home to the Lenca, Maya, and other indigenous peoples. Copán was one of the great Maya cities. The term "banana republic" was literally coined for Honduras, where United Fruit Company dominated politics and economy from the late 19th century. A series of military governments and US interventions defined the 20th century. Honduras today has one of the world''s highest homicide rates, driving mass migration to the US.'),
('JM', 'Jamaica was home to the Taíno people when Columbus arrived in 1494. Britain colonised the island; Jamaica became one of the Atlantic world''s largest sugar producers, worked by over 300,000 enslaved Africans. The Maroons — escaped enslaved people — fought two wars against the British. Independence came in 1962. Jamaica gave the world reggae music, Bob Marley, Rastafarianism, and sprint dominance at the Olympics.'),
('MX', 'Mexico was home to the Olmec, Maya, Toltec, and Aztec civilisations. The Aztec capital Tenochtitlan was one of the world''s largest cities when Hernán Cortés conquered it in 1521. The colonial "New Spain" was Spain''s most important possession. Independence in 1821 was followed by territorial loss to the US (1848). The 1910 Revolution — led by Zapata and Villa — shaped modern Mexico. The EZLN Zapatista uprising in 1994 coincided with NAFTA''s launch.'),
('NI', 'Nicaragua was briefly part of Central America''s union before becoming an independent republic in 1838. US Marines occupied Nicaragua repeatedly from 1912–1933; Augusto Sandino led armed resistance. The Somoza family''s dynastic dictatorship ended with the 1979 Sandinista revolution. Daniel Ortega returned to the presidency in 2007 and has ruled increasingly autocratically since.'),
('PA', 'Panama''s geography — the narrow isthmus connecting North and South America — made it a transit route of global importance. Gold from Peru crossed Panama by mule to Spanish galleons. Panama declared independence from Colombia in 1903 with American backing, enabling the US to build the Panama Canal, opened in 1914. The US returned full canal control in 1999. Panama''s service-based economy and canal revenues have made it one of Latin America''s wealthiest nations.'),
('KN', 'Saint Kitts was the first British and French colony in the Caribbean, settled from 1623. Fierce battles between Britain and France characterised the 17th and 18th centuries. Sugar was the economic foundation for centuries. Independence came in 1983 — making it the Americas'' newest state. The federation is now a tourism and offshore finance economy.'),
('LC', 'Saint Lucia changed hands between Britain and France 14 times — earning it the nickname "Helen of the West Indies." The Pitons — two dramatic volcanic spires — are a UNESCO World Heritage Site and global icon. Independence came in 1979. Saint Lucia has produced two Nobel laureates — the most per capita of any country in the world: economist W. Arthur Lewis and poet Derek Walcott.'),
('VC', 'Saint Vincent''s Carib (Garifuna) population resisted European colonisation longer than most Caribbean islands, with Britain only fully controlling it after the First and Second Carib Wars in the late 18th century. Independence came in 1979. The Soufrière volcano erupted massively in April 2021, displacing 20,000 people. The Grenadines'' sailing waters are among the Caribbean''s most beautiful.'),
('TT', 'Trinidad was inhabited by the Arawak and Carib before Spanish then British colonisation. Britain brought indentured workers from India after emancipation, creating an extraordinarily diverse society. Independence came in 1962. Trinidad is the birthplace of the steel pan and calypso music, and of Carnival — one of the world''s greatest festivals. A significant oil and natural gas economy has given Trinidad the highest human development index in the Caribbean.'),
('US', 'The United States declared independence from Britain in 1776, founding a democratic republic on Enlightenment principles. The Constitution (1787) and Bill of Rights created institutions that have proved remarkably durable. Westward expansion displaced and decimated Native American nations. The Civil War (1861–1865) ended slavery. The US emerged from WWI and WWII as the world''s dominant power. The Cold War, Civil Rights Movement, moon landing, and technological revolution all unfolded in the 20th century. The US remains the world''s largest economy and most powerful military force.'),

-- OCEANIA
('AU', 'Australia''s Aboriginal and Torres Strait Islander peoples have lived on the continent for at least 65,000 years — one of humanity''s oldest continuous cultures. Britain established the first European colony at Sydney Cove in 1788 as a penal settlement. Six colonies federated in 1901. Australia fought in both World Wars; the Gallipoli campaign is deeply embedded in national identity. Post-WWII immigration transformed Australia into a multicultural nation. Australia is the world''s largest exporter of iron ore, coal, and liquefied natural gas.'),
('FJ', 'Fiji''s Melanesian and Polynesian peoples settled the islands over 3,500 years ago. Britain annexed Fiji in 1874; indentured labourers from India were brought to work sugarcane, creating an Indo-Fijian community that now constitutes 38% of the population. Independence came in 1970. Two military coups in 1987 and two more in 2000 and 2006 have created political instability, partly rooted in ethnic tensions between indigenous Fijians and Indo-Fijians.'),
('KI', 'Kiribati (pronounced "Kiribas") consists of 33 atolls scattered across 3.5 million square kilometres of the Pacific. The Gilbert Islands saw fierce WWII fighting at Tarawa (1943). Independence came in 1979. Kiribati faces an existential threat from sea-level rise — most of its land sits barely a metre above sea level. The government has purchased land in Fiji as a potential refuge.'),
('MH', 'The Marshall Islands'' low-lying atolls were settled by Micronesians around 2000 BCE. The US used Bikini and Enewetak atolls for 67 nuclear tests between 1946–1958, exposing Marshallese to devastating radiation and displacing communities permanently. The islands gained independence in 1986 in free association with the US. Like Kiribati, the Marshall Islands faces existential risk from sea-level rise; the highest point is only 2 metres above sea level.'),
('FM', 'The Federated States of Micronesia''s four states — Yap, Chuuk, Pohnpei, and Kosrae — were settled by Austronesian and Melanesian peoples thousands of years ago. Nan Madol, built on artificial islands off Pohnpei around 1200 CE, is one of the Pacific''s most remarkable ancient sites. Spain, Germany, Japan, and the US administered the islands successively. Independence in free association with the US came in 1986. Chuuk Lagoon, where Japan''s Pacific Fleet was sunk in WWII, is a world-famous wreck diving site.'),
('NR', 'Nauru is the world''s smallest island state and the only republic without an official capital. Settled by Micronesians 3,000 years ago, Germany colonised Nauru in 1888. Massive phosphate deposits briefly made Nauru one of the world''s wealthiest nations per capita in the 1970s. Exhaustion of phosphate reserves left the island devastated environmentally and economically. Nauru now processes asylum seekers for Australia and relies heavily on aid.'),
('NZ', 'Māori ancestors navigated from Polynesia to Aotearoa (New Zealand) around 1250–1300 CE — the last major landmass to be settled by humans. Abel Tasman was the first European to sight it (1642); James Cook charted it in 1769. The Treaty of Waitangi (1840) established a British colony. New Zealand was the first self-governing country to grant women the right to vote (1893). New Zealand has pioneered nuclear-free zones, indigenous rights, and progressive governance.'),
('PW', 'Palau''s Rock Islands, rising from jewel-blue waters, contain one of the Pacific''s most ancient and continuous cultures — settlement dates to at least 3,000 years ago. Spain, Germany, Japan, and the US all administered Palau. WWII''s Battle of Peleliu (1944) was one of the Pacific''s bloodiest battles. Independence in free association with the US came in 1994. Palau was the world''s first country to create a marine sanctuary (2009).'),
('PG', 'Papua New Guinea is one of the world''s most linguistically diverse countries — 839 languages among 10 million people. Human habitation extends 40,000–60,000 years. Agriculture in the PNG highlands may be among the world''s oldest, dating to 7000 BCE. Germany controlled the northeast, Britain the south before Australian administration; independence came in 1975. PNG has extraordinary biodiversity and vast mineral resources including gold, copper, and natural gas.'),
('WS', 'Samoa has been inhabited by Polynesian people for over 3,000 years and is considered the "Cradle of Polynesia" — the ancestral homeland from which Polynesian peoples spread across the Pacific. Germany and the US divided Samoa in 1899; Western Samoa gained independence in 1962 — the first Pacific Island nation to do so. Samoa changed its position west of the international date line in 2011 to align business hours with Australia and New Zealand.'),
('SB', 'The Solomon Islands'' Melanesian peoples have inhabited the archipelago for at least 30,000 years. The islands were the site of ferocious WWII fighting — the Guadalcanal campaign (1942–1943) was a turning point in the Pacific War. Britain administered the islands; independence came in 1978. Civil conflict between 1998–2003 required Australian-led intervention. China has recently displaced Australia as the dominant external influence, signing a security agreement in 2022.'),
('TO', 'Tonga is the only Pacific Island monarchy and one of the few nations in the world never colonised by a European power. The Tongan Empire of the 10th–13th centuries controlled a vast maritime network across the central Pacific. Christianity is now central to Tonga''s identity. The 2022 Hunga Tonga volcanic eruption, one of the most powerful ever recorded, devastated the islands. Rugby union is a national passion.'),
('TV', 'Tuvalu consists of nine low-lying coral atolls with a maximum elevation of 4.5 metres above sea level. Polynesian settlement dates back thousands of years. Britain administered Tuvalu; independence came in 1978. Tuvalu has become the world''s most prominent voice in climate change diplomacy — its very existence threatened by rising seas. In 2023, Tuvalu signed a unique agreement with Australia offering Tuvaluans permanent residence rights as climate refugees.'),
('VU', 'Vanuatu''s 80 islands were jointly administered by Britain and France as the New Hebrides Condominium — one of history''s most unusual colonial arrangements, with dual administrations, police forces, and currencies. John Frum, the famous "cargo cult" that awaits an American deliverer''s return with goods, originated in Vanuatu. Independence came in 1980. Vanuatu is one of the world''s most disaster-prone nations — regularly hit by cyclones, earthquakes, and volcanic eruptions.'),

-- SOUTH AMERICA
('AR', 'Argentina''s vast Pampas grasslands, Andean peaks, and Patagonian wilderness were home to indigenous peoples before Spain colonised in the 16th century. Independence came in 1816 under José de San Martín. Argentina was one of the world''s ten wealthiest nations in 1900. The 20th century brought Peronism, military dictatorships, the Dirty War (1976–1983) with 30,000 disappeared, and chronic economic crises. Argentina also gave the world the tango and Diego Maradona.'),
('BO', 'Bolivia was the heart of the Tiwanaku Empire and later the Inca Empire''s most sacred site — Lake Titicaca, at 3,812 metres the world''s highest navigable lake. Spanish conquerors discovered the Cerro Rico mine at Potosí in 1545 — so rich it funded the entire Spanish Empire for centuries. Bolivia has lost territory in wars with Chile, Brazil, and Paraguay, losing its Pacific Ocean access in the War of the Pacific (1884). Evo Morales became Latin America''s first indigenous president in 2006.'),
('BR', 'Brazil is the world''s largest Portuguese-speaking nation. The Portuguese arrived in 1500; the vast Amazon basin and interior were gradually explored and colonised. Brazil imported more enslaved Africans than any other country — an estimated 4.9 million — shaping its extraordinary cultural diversity. The royal family fled from Napoleon to Brazil in 1808; independence came peacefully in 1822. Brazil abolished slavery last in the Americas (1888). Brazil is now Latin America''s largest economy.'),
('CL', 'Chile''s long, thin strip of land along South America''s Pacific coast was home to the Mapuche people, who uniquely resisted both Inca and Spanish conquest for centuries. Independence came in 1818 under Bernardo O''Higgins. Chile won the War of the Pacific (1879–1884), gaining nitrate-rich territories. The 1973 coup against elected socialist Salvador Allende by General Pinochet — backed by the CIA — installed a brutal dictatorship that lasted until 1990. Chile is the world''s largest copper producer.'),
('CO', 'Colombia was the heartland of the legendary El Dorado myths that drew Spanish conquistadors. The Muisca people of the highlands performed gold-gilding ceremonies on Lake Guatavita. Simón Bolívar liberated Colombia and dreamed of a united Gran Colombia. Decades of conflict with FARC guerrillas and drug cartels — Medellín''s Pablo Escobar being the most notorious — gave way to a 2016 peace deal. Colombia is the world''s largest cocaine producer.'),
('EC', 'Ecuador straddles the equator (hence the name) and is one of the world''s most biodiverse countries — the Galápagos Islands inspired Darwin''s theory of evolution. Pre-Inca cultures and then the Inca Empire ruled before Spanish conquest. Quito, high in the Andes, was the Inca''s northern capital. Ecuador was the first country in the world to grant rights to nature in its constitution (2008). It is OPEC''s smallest member and a major banana exporter.'),
('GY', 'The only English-speaking country in South America, Guyana was colonised by the Dutch before Britain took control in 1814. The sugarcane economy imported indentured labourers from India after emancipation, creating a society roughly split between Afro-Guyanese and Indo-Guyanese. Independence came in 1966. In 1978, Jonestown saw the mass death of 918 people. Massive offshore oil discoveries from 2015 are transforming Guyana into one of the world''s fastest-growing economies.'),
('PY', 'Paraguay''s Guaraní people are among South America''s most numerous indigenous groups, and Guaraní remains an official language alongside Spanish. The War of the Triple Alliance (1864–1870) — Paraguay versus Brazil, Argentina, and Uruguay — killed 60–70% of Paraguay''s population, including most of its adult men. Alfredo Stroessner''s dictatorship lasted 35 years (1954–1989). The Itaipú Dam is the world''s largest hydroelectric power station.'),
('PE', 'Peru was the heartland of the Inca Empire — the largest empire in pre-Columbian America, stretching from Ecuador to Argentina. Machu Picchu, built around 1450 CE and abandoned after the Spanish conquest, is one of the world''s most iconic archaeological sites. Francisco Pizarro conquered the Incas with a few hundred men in 1532. Lima became the capital of Spain''s South American empire. Peru''s history since has been punctuated by coups, the Shining Path Maoist insurgency, and the extraordinary productivity of its Pacific fisheries and mining sector.'),
('SR', 'Suriname is the only country in the Americas where Dutch is the official language — a legacy of Dutch colonisation from 1667, when the Dutch traded New Amsterdam (New York) to the British for Suriname. Enslaved Africans worked the plantations; Maroon communities of escaped slaves established autonomous kingdoms in the interior. Indian and Javanese indentured workers arrived after emancipation, creating one of the world''s most diverse small nations. Independence came in 1975.'),
('UY', 'Uruguay was a buffer state between Spanish and Portuguese colonial empires, gaining independence only in 1828 as a compromise between Brazil and Argentina. Despite its small size, Uruguay has historically been a pioneer of social reform — the first Latin American country to establish a welfare state, legalise divorce, and separate church from state in the early 20th century. In 2012, Uruguay became the first country to legalise the state-controlled sale of cannabis. It regularly ranks as Latin America''s most democratic and least corrupt nation.');
